CREATE OR REPLACE FUNCTION OFSERM.ENTITY_INFO_HIER_DATA_POP(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FCT_ENTITY_INFO(N_BANK_CAP_CONSL_APPR_SKEY,N_BASEL_CONSL_OPTN_TYPE_SKEY,N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_GAAP_SKEY,F_SIB_TYPE_IND,N_PARTY_SKEY,N_ENTITY_TYPE_SKEY,F_CAP_CONSL_ENTITY_IND,F_CAP_CONSL_PARENT_ENTITY_IND,F_REGULATORY_ENTITY_IND,F_ULTIMATE_PARENT_ENTITY_FLAG,N_ACCOUNTING_CAPITAL_SURPLUS,N_ADDITIONAL_TIER1_AMOUNT,N_AVG_CONSOLIDATED_ASSETS,N_COMMON_EQUITY_TIER1_AMOUNT,N_HOLDING_COMPANY_TYPE_SKEY,N_PARENT_ENTITY_SKEY,N_RUN_SKEY,N_TIER2_AMOUNT,V_CAPITAL_ADEQUACY_REGULATOR,V_PARTY_ID,N_EXCHANGE_RATE,N_ENTITY_SKEY,F_CURR_QTR_PROFIT_INCL_IN_CET1,F_GSIB_FLAG,F_SMALL_BUSS_SEC_TREAT_ELIG,F_SUPERVISOR_APPRV_SURPL_DEFC,N_ADDITIONAL_TIER1_AMT_NCY,N_AVG_ANNUAL_DIV_LAST_3_YRS,N_AVG_CONSOLIDATED_ASSETS_NCY,N_CAP_SURPLUS_DEFICIT_AMT,N_COMMON_EQUITY_TIER1_AMT_NCY,N_LOSS_ABSORBENCY_BUCKET,N_LOSS_ABS_OVERRIDE,N_NET_PROFIT_UPTO_CURR_QUARTER,N_THIRD_PARTY_INVST_AT1_PCT,N_THIRD_PARTY_INVST_CET1_PCT,N_THIRD_PARTY_INVST_T2_PCT,N_TIER2_AMT_NCY,V_CCY_CODE,V_ENTITY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_BANK_CAP_CONSL_APPR.N_BANK_CAP_CONSL_APPR_SKEY),to_char(DIM_BASEL_CONSL_OPTION_TYPE.N_BASEL_CONSL_OPTN_TYPE_SKEY),to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),DIM_PARTY.F_SIB_TYPE_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),'Y',CASE WHEN  FSI_ORG_HIER_FLAT.N_ENTITY_SKEY = DIM_ORG_STRUCTURE.N_ENTITY_SKEY THEN 'Y' END,DIM_ORG_STRUCTURE_FLAT.F_REGULATORY_ENTITY_IND,CASE WHEN  FSI_ORG_HIER_FLAT.N_ENTITY_SKEY = DIM_ORG_STRUCTURE.N_ENTITY_SKEY THEN 'Y' END,STG_LEGAL_ENTITY_DETAILS.N_ACCOUNTING_CAPITAL_SURPLUS * FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_LEGAL_ENTITY_DETAILS.N_ADDITIONAL_TIER1_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_LEGAL_ENTITY_DETAILS.N_AVG_CONSOLIDATED_ASSETS * FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,STG_LEGAL_ENTITY_DETAILS.N_COMMON_EQUITY_TIER1_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,DIM_HOLDING_COMPANY_TYPE.N_HOLDING_COMPANY_TYPE_SKEY,Z.N_ENTITY_SKEY,'870',STG_LEGAL_ENTITY_DETAILS.N_TIER2_AMOUNT * FSI_CAP_CURRENCY_CONVERSION.n_exchange_rate,COALESCE(FSI_SETUP_JURISDICTION_INFO.V_CAPITAL_ADEQUACY_REGULATOR, DIM_PARTY.V_CAPITAL_ADEQUACY_REGULATOR),DIM_ORG_STRUCTURE_FLAT.V_PARTY_ID,to_char(FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE),to_char(FSI_ORG_HIER_FLAT.N_ENTITY_SKEY),STG_LEGAL_ENTITY_DETAILS.F_CURR_QTR_PROFIT_INCL_IN_CET1,STG_LEGAL_ENTITY_DETAILS.F_GSIB_FLAG,STG_LEGAL_ENTITY_DETAILS.F_SMALL_BUSS_SEC_TREAT_ELIG,STG_LEGAL_ENTITY_DETAILS.F_SUPERVISOR_APPRV_SURPL_DEFC,to_char(STG_LEGAL_ENTITY_DETAILS.N_ADDITIONAL_TIER1_AMOUNT),to_char(STG_LEGAL_ENTITY_DETAILS.N_AVG_ANNUAL_DIV_LAST_3_YRS),to_char(STG_LEGAL_ENTITY_DETAILS.N_AVG_CONSOLIDATED_ASSETS),to_char(STG_LEGAL_ENTITY_DETAILS.N_CAP_SURPLUS_DEFICIT_AMT),to_char(STG_LEGAL_ENTITY_DETAILS.N_COMMON_EQUITY_TIER1_AMOUNT),to_char(STG_LEGAL_ENTITY_DETAILS.N_LOSS_ABSORBENCY_BUCKET),to_char(STG_LEGAL_ENTITY_DETAILS.N_LOSS_ABS_OVERRIDE),to_char(STG_LEGAL_ENTITY_DETAILS.N_NET_PROFIT_UPTO_CURR_QUARTER),to_char(STG_LEGAL_ENTITY_DETAILS.N_THIRD_PARTY_INVST_AT1_PCT),to_char(STG_LEGAL_ENTITY_DETAILS.N_THIRD_PARTY_INVST_CET1_PCT),to_char(STG_LEGAL_ENTITY_DETAILS.N_THIRD_PARTY_INVST_T2_PCT),to_char(STG_LEGAL_ENTITY_DETAILS.N_TIER2_AMOUNT),STG_LEGAL_ENTITY_DETAILS.V_CCY_CODE,STG_LEGAL_ENTITY_DETAILS.V_LV_CODE FROM STG_LEGAL_ENTITY_DETAILS INNER JOIN DIM_DATES ON STG_LEGAL_ENTITY_DETAILS.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN FSI_CAP_RUN_EXE_PARAMETERS ALIAS_FSI_CAP_RUN_EXE_PARAMETERS ON ALIAS_FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' INNER JOIN DIM_ORG_STRUCTURE DIM_ORG_STRUCTURE_FLAT ON DIM_ORG_STRUCTURE_FLAT.V_ENTITY_CODE = STG_LEGAL_ENTITY_DETAILS.V_LV_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE_FLAT.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE_FLAT.D_RECORD_END_DATE INNER JOIN ( DIM_ORG_STRUCTURE INNER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY = '870' AND DIM_ORG_STRUCTURE.N_ENTITY_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_ENTITY_SKEY INNER JOIN FSI_ORG_HIER_FLAT ON FSI_ORG_HIER_FLAT.N_CONSL_PARENT_SKEY = DIM_ORG_STRUCTURE.N_ENTITY_SKEY ) ON FSI_ORG_HIER_FLAT.N_ENTITY_SKEY = DIM_ORG_STRUCTURE_FLAT.N_ENTITY_SKEY LEFT OUTER JOIN DIM_PARTY ON DIM_ORG_STRUCTURE_FLAT.V_PARTY_ID = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.d_record_start_date AND DIM_PARTY.d_record_end_date INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.d_record_start_date AND DIM_PARTY_TYPE.d_record_end_date INNER JOIN DIM_COUNTRY ON DIM_COUNTRY.V_COUNTRY_ID = COALESCE(STG_LEGAL_ENTITY_DETAILS.V_COUNTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_GAAP ON STG_LEGAL_ENTITY_DETAILS.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.d_record_start_date AND DIM_GAAP.d_record_end_date LEFT OUTER JOIN DIM_BANK_CAP_CONSL_APPR ON STG_LEGAL_ENTITY_DETAILS.V_CAP_CONSL_APPROACH = DIM_BANK_CAP_CONSL_APPR.V_BANK_CAP_CONSL_APPR_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_BANK_CAP_CONSL_APPR.d_record_start_date AND DIM_BANK_CAP_CONSL_APPR.d_record_end_date LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY = '870' AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_LEGAL_ENTITY_DETAILS.V_CCY_CODE LEFT OUTER JOIN DIM_HOLDING_COMPANY_TYPE ON DIM_HOLDING_COMPANY_TYPE.V_HOLDING_COMPANY_TYPE = DIM_ORG_STRUCTURE.V_HOLDING_COMPANY_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_HOLDING_COMPANY_TYPE.d_record_start_date AND DIM_HOLDING_COMPANY_TYPE.d_record_end_date INNER JOIN DIM_BASEL_CONSL_OPTION_TYPE ON DIM_BASEL_CONSL_OPTION_TYPE.N_BASEL_CONSL_OPTN_TYPE_SKEY = ALIAS_FSI_CAP_RUN_EXE_PARAMETERS.N_BASEL_CONSL_TYPE_SKEY LEFT OUTER JOIN DIM_ORG_STRUCTURE Z ON to_date('20260331','YYYYMMDD') BETWEEN Z.D_RECORD_START_DATE AND Z.D_RECORD_END_DATE AND Z.V_ENTITY_CODE = DIM_ORG_STRUCTURE.V_PARENT_CODE LEFT OUTER JOIN FSI_SETUP_JURISDICTION_INFO ON FSI_SETUP_JURISDICTION_INFO.V_JURISDICTION_CODE = ALIAS_FSI_CAP_RUN_EXE_PARAMETERS.V_JURISDICTION_CODE AND FSI_SETUP_JURISDICTION_INFO.V_APPLICATION_CODE = 'BASEL' WHERE 1=1 AND 1=1 AND ( ( DIM_BASEL_CONSL_OPTION_TYPE.V_BASEL_CONSL_OPTN_TYPE_CODE = 'SOLO' AND FSI_ORG_HIER_FLAT.N_HIER_LEVEL = 0 ) OR (DIM_BASEL_CONSL_OPTION_TYPE.V_BASEL_CONSL_OPTN_TYPE_CODE = 'CONSL') ) LOG ERRORS INTO FCT_ENTITY_INFO$ ('1776767939339_80358651_20260331_1_Job_bb61d9926a24431ebc392b8e1496f867') REJECT LIMIT UNLIMITED;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
